pub struct AbortReq {
    pub rid: rmpv::Value,
    pub http_worker_ipc: rmpv::Value,
    pub abort_all: rmpv::Value,
    pub finished_reason: rmpv::Value,
    pub abort_message: rmpv::Value,
}

impl AbortReq {
    pub fn encode(&self) -> Result<Vec<u8>, Error> {
        use rmpv::Value;
        let arr = Value::Array(vec![
            Value::from("AbortReq"),
            self.rid.clone(),
            self.http_worker_ipc.clone(),
            self.abort_all.clone(),
            self.finished_reason.clone(),
            self.abort_message.clone(),
        ]);
        let mut buf = Vec::new();
        rmpv::encode::write_value(&mut buf, &arr).map_err(|e| Error::Codec(e.to_string()))?;
        Ok(buf)
    }

    pub fn decode(data: &[u8]) -> Result<Self, Error> {
        use rmpv::Value;
        const TAG: &str = "AbortReq";
        let val: Value =
            rmpv::decode::read_value(&mut &data[..]).map_err(|e| Error::Codec(e.to_string()))?;
        let arr = val
            .as_array()
            .ok_or_else(|| Error::Codec("expected array".to_string()))?;

        // Validate tag (index 0)
        let tag = arr
            .first()
            .and_then(|v| v.as_str())
            .ok_or_else(|| Error::Codec("missing tag".to_string()))?;
        if tag != TAG {
            return Err(Error::Codec(format!("expected tag {TAG}, got {tag}")));
        }

        // Validate array length (expected 6: tag + 5 fields)
        if arr.len() != 6 {
            return Err(Error::Codec(format!(
                "expected 6 elements, got {}",
                arr.len()
            )));
        }

        let rid: rmpv::Value = arr.get(1).cloned().unwrap_or(rmpv::Value::Nil);
        let http_worker_ipc: rmpv::Value = arr.get(2).cloned().unwrap_or(rmpv::Value::Nil);
        let abort_all: rmpv::Value = arr.get(3).cloned().unwrap_or(rmpv::Value::Nil);
        let finished_reason: rmpv::Value = arr.get(4).cloned().unwrap_or(rmpv::Value::Nil);
        let abort_message: rmpv::Value = arr.get(5).cloned().unwrap_or(rmpv::Value::Nil);

        Ok(Self {
            rid,
            http_worker_ipc,
            abort_all,
            finished_reason,
            abort_message,
        })
    }
}

